head = b"I am Mallory"
body = chr(0).encode() * 1
tail = b"own CryptoHack.org" 
msg = head + body + tail
print(msg)

digest = emsa_pkcs1_v15.encode(msg, 256)
check = bytes_to_long(digest)
payload = {"option": "get_signature", "N": hex(sign - check), "e": hex(1), "msg": msg.decode()}

r.sendline(json.dumps(payload).encode())
res = json.loads(r.recvline().decode())
            
n = int(res['N'], 16)
e = int(res['E'], 16)
sign = int(res['signature'], 16)

print('n =', n)
print('e =', e)
print('sign =', sign)
